class Solution:
    def convertPostfixToPrefix(self, postfix: str) -> str:
        stack = []
        tokens = postfix.split()
        for token in tokens:
            if token.isalnum():
                stack.append(token)
            else:
                operand2 = stack.pop()
                operand1 = stack.pop()
                prefix_expression = f"{token} {operand1} {operand2}"
                stack.append(prefix_expression)
        return stack[0]

