#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string convertPostfixToPrefix(string postfix) {
        stack<string> st;
        stringstream ss(postfix);
        string token;
        while (ss >> token) {
            if (isalpha(token[0])) {
                st.push(token);
            } else {
                string operand2 = st.top(); st.pop();
                string operand1 = st.top(); st.pop();
                string prefix_expression = token + " " + operand1 + " " + operand2;
                st.push(prefix_expression);
            }
        }
        return st.top();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    cin.ignore();
    string postfix;
    getline(cin, postfix);
    Solution sol;
    string ans = sol.convertPostfixToPrefix(postfix);
    cout << ans << "\n";
    return 0;
}
